select
id, year, club_code, io_type, trade_type, trade_time, subject, amount, creator, remark, create_time, update_time
from tb_club


        and id = #{query.id}


        and year = #{query.year}


        and club_code = #{query.clubCode}


        and io_type = #{query.ioType}


        and trade_type = #{query.tradeType}


        and trade_time = #{query.tradeTime}


